import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

// Known CEX hot wallet examples (replace with actual)
const CEX_WALLETS = [
  "0x28C6c06298d514Db089934071355E5743bf21d60", // Binance
  "0xDFd5293D8e347dFe59E90eFd55b2956a1343963d", // Coinbase
];

async function getExchangeFlows(chainName, tokenAddress) {
  const flows = await Promise.all(
    CEX_WALLETS.map(wallet =>
      client.BalanceService.getErc20TransfersForWalletAddress(chainName, wallet, { contractAddress: tokenAddress })
    )
  );
  return flows.map((f, i) => ({ exchange: CEX_WALLETS[i], transfers: f.data?.items }));
}
